arguments.file_text:
@using sv_1f67f91f03264bcb8c782d7793c87e89.Services

<div>
    <h2 class="section-title">Profile</h2>

    @if (_profile is null)
    {
        <p>Loading…</p>
    }
    else
    {
        <div class="profile-layout">
            <div class="profile-form">
                <div class="form-group">
                    <label for="displayName">Display Name</label>
                    <input id="displayName" type="text" @bind="_displayName" />
                </div>

                <div class="form-group">
                    <label for="email">Email</label>
                    <input id="email" type="email" @bind="_email" />
                </div>

                <div class="form-group">
                    <label for="bio">Bio</label>
                    <textarea id="bio" rows="4" @bind="_bio"></textarea>
                </div>

                <div class="form-group">
                    <label for="avatarUrl">Avatar URL</label>
                    <input id="avatarUrl" type="text" @bind="_avatarUrl" />
                </div>

                <div class="btn-group">
                    <button class="btn btn-primary" @onclick="SaveAsync">Save Changes</button>
                    <button class="btn btn-secondary" @onclick="Discard">Discard Changes</button>
                </div>
            </div>

            <div class="avatar-preview">
                <h5>Avatar Preview</h5>
                <div class="avatar-frame">
                    <img src="@_avatarUrl" alt="Avatar" />
                </div>
                <small class="avatar-url-display">@_avatarUrl</small>
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;
    [Parameter] public EventCallback<string> OnNotify { get; set; }

    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";

    protected override async Task OnInitializedAsync()
    {
        _profile = await SettingsService.GetProfileAsync();
        LoadFromProfile(_profile);
    }

    private void LoadFromProfile(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _bio = p.Bio;
        _avatarUrl = p.AvatarUrl;
    }

    private async Task SaveAsync()
    {
        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(updated);
        _profile = updated;
        await OnNotify.InvokeAsync("Profile saved successfully.");
    }

    private void Discard()
    {
        if (_profile is not null)
            LoadFromProfile(_profile);
    }
}

.profile-layout {
    display: flex;
    gap: 2rem;
    flex-wrap: wrap;
}

.profile-form {
    flex: 1;
    min-width: 300px;
}

.avatar-preview {
    width: 200px;
    text-align: center;
}

.avatar-preview h5 {
    font-size: 0.9rem;
    font-weight: 600;
    color: #555;
    margin-bottom: 0.75rem;
}

.avatar-frame {
    width: 150px;
    height: 150px;
    margin: 0 auto 0.5rem;
    border-radius: 50%;
    overflow: hidden;
    border: 3px solid #e0e0e0;
}

.avatar-frame img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-url-display {
    display: block;
    word-break: break-all;
    color: #888;
    font-size: 0.75rem;
}

@using sv_1f67f91f03264bcb8c782d7793c87e89.Services

<div>
    <h2 class="section-title">Notifications</h2>

    @if (_prefs is null)
    {
        <p>Loading…</p>
    }
    else
    {
        <div class="card">
            <div class="card-title">Notification Channels</div>

            <div class="toggle-row">
                <label>Email Notifications</label>
                <label class="toggle-switch">
                    <input type="checkbox" @bind="_emailNotifications" />
                    <span class="toggle-slider"></span>
                </label>
            </div>

            <div class="toggle-row">
                <label>Push Notifications</label>
                <label class="toggle-switch">
                    <input type="checkbox" @bind="_pushNotifications" />
                    <span class="toggle-slider"></span>
                </label>
            </div>

            <div class="toggle-row">
                <label>Weekly Digest</label>
                <label class="toggle-switch">
                    <input type="checkbox" @bind="_weeklyDigest" />
                    <span class="toggle-slider"></span>
                </label>
            </div>
        </div>

        <div class="card">
            <div class="card-title">Muted Channels</div>
            <div class="channel-list">
                @foreach (var channel in MockSettingsService.AllChannels)
                {
                    <label class="channel-item">
                        <input type="checkbox"
                               checked="@_mutedChannels.Contains(channel)"
                               @onchange="e => ToggleMute(channel, (bool)e.Value!)" />
                        <span>@channel</span>
                        @if (_mutedChannels.Contains(channel))
                        {
                            <span class="mute-badge">muted</span>
                        }
                    </label>
                }
            </div>
        </div>

        <div class="btn-group">
            <button class="btn btn-primary" @onclick="SaveAsync">Save Preferences</button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;
    [Parameter] public EventCallback<string> OnNotify { get; set; }

    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();

    protected override async Task OnInitializedAsync()
    {
        _prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = _prefs.EmailNotifications;
        _pushNotifications = _prefs.PushNotifications;
        _weeklyDigest = _prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(_prefs.MutedChannels);
    }

    private void ToggleMute(string channel, bool isMuted)
    {
        if (isMuted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        var updated = new NotificationPrefs(
            _emailNotifications,
            _pushNotifications,
            _weeklyDigest,
            _mutedChannels.ToList()
        );
        await SettingsService.SaveNotificationPrefsAsync(updated);
        _prefs = updated;
        await OnNotify.InvokeAsync("Notification preferences saved.");
    }
}

.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.4rem 0;
    cursor: pointer;
    font-size: 0.9rem;
    color: #444;
}

.channel-item input[type="checkbox"] {
    width: 16px;
    height: 16px;
    accent-color: #1a73e8;
}

.mute-badge {
    font-size: 0.7rem;
    background: #ffeaa7;
    color: #856404;
    padding: 0.1rem 0.4rem;
    border-radius: 4px;
    font-weight: 500;
}

@using sv_1f67f91f03264bcb8c782d7793c87e89.Services

<div>
    <h2 class="section-title">Security</h2>

    @if (_security is null)
    {
        <p>Loading…</p>
    }
    else
    {
        <!-- Change Password -->
        <div class="card">
            <div class="expandable-header" @onclick="() => _passwordExpanded = !_passwordExpanded">
                <span class="card-title" style="margin-bottom:0">Change Password</span>
                <span class="expand-icon">@(_passwordExpanded ? "▲" : "▼")</span>
            </div>

            @if (_passwordExpanded)
            {
                <div class="expandable-body">
                    <div class="form-group">
                        <label for="currentPwd">Current Password</label>
                        <input id="currentPwd" type="password" @bind="_currentPassword" />
                    </div>
                    <div class="form-group">
                        <label for="newPwd">New Password</label>
                        <input id="newPwd" type="password" @bind="_newPassword" />
                    </div>
                    <div class="form-group">
                        <label for="confirmPwd">Confirm Password</label>
                        <input id="confirmPwd" type="password" @bind="_confirmPassword" />
                    </div>
                    @if (!string.IsNullOrEmpty(_passwordError))
                    {
                        <div class="field-error">@_passwordError</div>
                    }
                    <button class="btn btn-primary" @onclick="ChangePasswordAsync">Update Password</button>
                </div>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="card">
            <div class="toggle-row">
                <div>
                    <label>Two-Factor Authentication</label>
                    <div class="status-indicator @(_twoFactorEnabled ? "status-on" : "status-off")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </div>
                </div>
                <label class="toggle-switch">
                    <input type="checkbox" @bind="_twoFactorEnabled" />
                    <span class="toggle-slider"></span>
                </label>
            </div>
            @if (_security.LastPasswordChange.HasValue)
            {
                <small class="text-muted">
                    Last password change: @_security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </small>
            }
        </div>

        <!-- Active Sessions -->
        <div class="card">
            <div class="card-title">Active Sessions</div>
