@using sv_1f67f91f03264bcb8c782d7793c87e89.Services

<div>
    <h2 class="section-title">Security</h2>

    @if (_security is null)
    {
        <p>Loading…</p>
    }
    else
    {
        <!-- Change Password -->
        <div class="card">
            <div class="expandable-header" @onclick="() => _passwordExpanded = !_passwordExpanded">
                <span class="card-title" style="margin-bottom:0">Change Password</span>
                <span class="expand-icon">@(_passwordExpanded ? "▲" : "▼")</span>
            </div>

            @if (_passwordExpanded)
            {
                <div class="expandable-body">
                    <div class="form-group">
                        <label for="currentPwd">Current Password</label>
                        <input id="currentPwd" type="password" @bind="_currentPassword" />
                    </div>
                    <div class="form-group">
                        <label for="newPwd">New Password</label>
                        <input id="newPwd" type="password" @bind="_newPassword" />
                    </div>
                    <div class="form-group">
                        <label for="confirmPwd">Confirm Password</label>
                        <input id="confirmPwd" type="password" @bind="_confirmPassword" />
                    </div>
                    @if (!string.IsNullOrEmpty(_passwordError))
                    {
                        <div class="field-error">@_passwordError</div>
                    }
                    <button class="btn btn-primary" @onclick="ChangePasswordAsync">Update Password</button>
                </div>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="card">
            <div class="toggle-row">
                <div>
                    <label>Two-Factor Authentication</label>
                    <div class="status-indicator @(_twoFactorEnabled ? "status-on" : "status-off")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </div>
                </div>
                <label class="toggle-switch">
                    <input type="checkbox" @bind="_twoFactorEnabled" />
                    <span class="toggle-slider"></span>
                </label>
            </div>
            @if (_security.LastPasswordChange.HasValue)
            {
                <small class="text-muted">
                    Last password change: @_security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </small>
            }
        </div>

        <!-- Active Sessions -->
        <div class="card">
            <div class="card-title">Active Sessions</div>
            <table class="sessions-table">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in _security.Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (session.Id != _security.Sessions.First().Id)
                                {
                                    @if (_confirmRevokeId == session.Id)
                                    {
                                        <div class="revoke-confirm">
                                            <span>Revoke this session?</span>
                                            <button class="btn btn-danger btn-sm" @onclick="() => RevokeSessionAsync(session.Id)">
                                                Confirm
                                            </button>
                                            <button class="btn btn-secondary btn-sm" @onclick="() => _confirmRevokeId = null">
                                                Cancel
                                            </button>
                                        </div>
                                    }
                                    else
                                    {
                                        <button class="btn btn-secondary btn-sm" @onclick="() => _confirmRevokeId = session.Id">
                                            Revoke
                                        </button>
                                    }
                                }
                                else
                                {
                                    <span class="current-badge">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;
    [Parameter] public EventCallback<string> OnNotify { get; set; }

    private SecuritySettings? _security;
    private bool _twoFactorEnabled;

    private bool _passwordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;

    private string? _confirmRevokeId;

    protected override async Task OnInitializedAsync()
    {
        _security = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = _security.TwoFactorEnabled;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _currentPassword = _newPassword = _confirmPassword = "";
        _passwordExpanded = false;
        await OnNotify.InvokeAsync("Password updated successfully.");
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _confirmRevokeId = null;
        await OnNotify.InvokeAsync("Session revoked.");
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

