toolArgs.file_text:
@using sv_1f67f91f03264bcb8c782d7793c87e89.Services

<div>
    <h2 class="section-title">Appearance</h2>

    @if (_settings is null)
    {
        <p>Loading…</p>
    }
    else
    {
        <div class="appearance-layout">
            <div class="appearance-form">
                <!-- Theme -->
                <div class="card">
                    <div class="card-title">Theme</div>
                    <div class="radio-group">
                        @foreach (var theme in new[] { "Light", "Dark", "System" })
                        {
                            <label class="radio-item">
                                <input type="radio" name="theme" value="@theme"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <span>@theme</span>
                            </label>
                        }
                    </div>
                </div>

                <!-- Font Size -->
                <div class="card">
                    <div class="card-title">Font Size</div>
                    <div class="radio-group">
                        @foreach (var size in new[] { "Small", "Medium", "Large" })
                        {
                            <label class="radio-item">
                                <input type="radio" name="fontSize" value="@size"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <span>@size</span>
                            </label>
                        }
                    </div>
                </div>

                <!-- Language -->
                <div class="card">
                    <div class="card-title">Language</div>
                    <div class="form-group">
                        <select @bind="_language">
                            <option value="English">English</option>
                            <option value="Spanish">Spanish</option>
                            <option value="French">French</option>
                            <option value="German">German</option>
                            <option value="Japanese">Japanese</option>
                            <option value="Chinese">Chinese</option>
                        </select>
                    </div>
                </div>

                <!-- Compact Mode -->
                <div class="card">
                    <div class="toggle-row">
                        <label>Compact Mode</label>
                        <label class="toggle-switch">
                            <input type="checkbox" @bind="_compactMode" />
                            <span class="toggle-slider"></span>
                        </label>
                    </div>
                </div>

                <div class="btn-group">
                    <button class="btn btn-primary" @onclick="SaveAsync">Save</button>
                </div>
            </div>

            <!-- Live Preview -->
            <div class="preview-panel" style="@PreviewStyle">
                <h5 class="preview-title">Live Preview</h5>
                <div class="preview-content">
                    <p class="preview-heading">Dashboard</p>
                    <p>Welcome back! Here's your activity summary for this week.</p>
                    <div class="preview-stats">
                        <div class="preview-stat">
                            <strong>142</strong>
                            <small>Tasks</small>
                        </div>
                        <div class="preview-stat">
                            <strong>28</strong>
                            <small>Messages</small>
                        </div>
                        <div class="preview-stat">
                            <strong>96%</strong>
                            <small>Uptime</small>
                        </div>
                    </div>
                    <button class="preview-btn">View Details</button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;
    [Parameter] public EventCallback<string> OnNotify { get; set; }

    private AppearanceSettings? _settings;
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetAppearanceAsync();
        _theme = _settings.Theme;
        _fontSize = _settings.FontSize;
        _language = _settings.Language;
        _compactMode = _settings.CompactMode;
    }

    private async Task SaveAsync()
    {
        var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(updated);
        _settings = updated;
        await OnNotify.InvokeAsync("Appearance settings saved.");
    }

    private string PreviewStyle
    {
        get
        {
            var bg = _theme switch { "Dark" => "#1e1e1e", "System" => "#2d2d3f", _ => "#ffffff" };
            var fg = _theme == "Light" ? "#333" : "#e0e0e0";
            var fs = _fontSize switch { "Small" => "0.8rem", "Large" => "1.1rem", _ => "0.95rem" };
            var pad = _compactMode ? "0.75rem" : "1.25rem";
            return $"background:{bg}; color:{fg}; font-size:{fs}; padding:{pad};";
        }
    }
}

.appearance-layout {
    display: flex;
    gap: 2rem;
    flex-wrap: wrap;
}

.appearance-form {
    flex: 1;
    min-width: 300px;
}

.radio-group {
    display: flex;
    gap: 1.25rem;
}

.radio-item {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    cursor: pointer;
    font-size: 0.9rem;
    color: #444;
}

.radio-item input[type="radio"] {
    accent-color: #1a73e8;
}

.preview-panel {
    width: 300px;
    min-width: 260px;
    border: 1px solid #ddd;
    border-radius: 8px;
    transition: all 0.3s ease;
    overflow: hidden;
}

.preview-title {
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    opacity: 0.6;
    margin-bottom: 0.75rem;
}

.preview-content {
    line-height: 1.5;
}

.preview-heading {
    font-weight: 700;
    font-size: 1.15em;
    margin-bottom: 0.3rem;
}

.preview-stats {
    display: flex;
    gap: 1rem;
    margin: 1rem 0;
}

.preview-stat {
    text-align: center;
    flex: 1;
}

.preview-stat strong {
    display: block;
    font-size: 1.3em;
}

.preview-stat small {
    opacity: 0.7;
    font-size: 0.8em;
}

.preview-btn {
    padding: 0.35rem 1rem;
    border: 1px solid currentColor;
    background: transparent;
    color: inherit;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.85em;
    opacity: 0.8;
}

